import java.util.*;

public class Main {
    public boolean[] checkFriends(int n, int[][] restrictions, int[][] requests) {
        List<Set<Integer>> friends = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            friends.add(new HashSet<>());
        }
        for (int[] restriction : restrictions) {
            friends.get(restriction[0]).add(restriction[1]);
            friends.get(restriction[1]).add(restriction[0]);
        }

        boolean[] result = new boolean[requests.length];
        for (int i = 0; i < requests.length; i++) {
            int a = requests[i][0];
            int b = requests[i][1];
            if (!friends.get(a).contains(b) && !friends.get(b).contains(a)) {
                friends.get(a).add(b);
                friends.get(b).add(a);
                result[i] = true;
            } else {
                result[i] = false;
            }
        }
        return result;
    }
}
```

